// === Public API ===

export function getFixedSemester(code: string): number | undefined {
  return FIXED_SEMESTER[code];
}

export function getFixedSemesterCodes(): string[] {
  return Object.keys(FIXED_SEMESTER);
}

export function getCurriculumPrereqs(code: string): string[] {
  return JSON_PREREQS[code] ?? DAA_BEFORE[code] ?? [];
}

export function getCurriculumCredits(code: string): number | undefined {
  return DAA_CREDITS[code];
}
